const items = $input.all().map(i => {
  const d = i.json;
  const curr = parseFloat(d.value || 0);
  const prev = parseFloat(d.previous || 0);
  const delta = prev > 0 ? ((curr - prev) / prev * 100).toFixed(1) : null;
  const vs_target = d.target ? ((curr / parseFloat(d.target)) * 100).toFixed(1) : null;
  const trend = delta > 0 ? 'up' : delta < 0 ? 'down' : 'flat';
  return { ...d, delta_pct: delta, vs_target_pct: vs_target, trend };
});
return [{ json: { week: new Date().toISOString().slice(0, 10), metrics: items } }];
